import{_ as t,a2 as a,y as i,B as r}from"./chunks/framework.BrfCoiDy.js";const f=JSON.parse('{"title":"📖 Definition of Terms","description":"","frontmatter":{},"headers":[],"relativePath":"03-definition-of-terms.md","filePath":"03-definition-of-terms.md"}'),o={name:"03-definition-of-terms.md"};function n(s,e,l,h,c,d){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="📖-definition-of-terms" tabindex="-1">📖 Definition of Terms <a class="header-anchor" href="#📖-definition-of-terms" aria-label="Permalink to “📖 Definition of Terms”">​</a></h1><p><strong>You can skip</strong> this part and proceed to the next sections. But if you&#39;d like, you can go through the terms to have a little background knowledge.</p><h3 id="parallel-circuit" tabindex="-1">Parallel Circuit <a class="header-anchor" href="#parallel-circuit" aria-label="Permalink to “Parallel Circuit”">​</a></h3><p>A circuit in which parts are connected through same terminals. In batteries, for example, positive of battery A is connected to the positive of battery B, and negative of battery A is connected to the negative of battery B. In batteries, this creates a greater capacity. The general rule is that, voltage stays the same, and currents either split or add.</p><h3 id="series-circuit" tabindex="-1">Series Circuit <a class="header-anchor" href="#series-circuit" aria-label="Permalink to “Series Circuit”">​</a></h3><p>A circuit in which parts are connected through the opposite terminals. In batteries, for example, positive of battery A is connected to negative of battery B (don&#39;t connect the other terminals together, it may explode ⚠️), and this will double the voltage. The general rule is that, the current stays the same, and voltage either divide or add.</p><h3 id="gearbox" tabindex="-1">Gearbox <a class="header-anchor" href="#gearbox" aria-label="Permalink to “Gearbox”">​</a></h3><p>A gearbox (or transmission) is a mechanical unit containing a gear train that transfers power from a source (like an dc motor) to another component (like wheels), controlling torque and rotational speed.</p><h3 id="torque" tabindex="-1">Torque <a class="header-anchor" href="#torque" aria-label="Permalink to “Torque”">​</a></h3><p>Torque is a measure of the rotational force (or &quot;twisting&quot; power) acting on an object. In the context of this project, torque refers to the amount of weight a motor can drive something without stalling. Higher torque, means higher twisting poster, means motor can drive greater weights without stalling.</p><h3 id="stalling" tabindex="-1">Stalling <a class="header-anchor" href="#stalling" aria-label="Permalink to “Stalling”">​</a></h3><p>Motor stalling means that the electric motor has more load on it than it is designed for and it can no longer supply enough torque (rotational power) to keep it spinning.</p>',12)])])}const m=t(o,[["render",n]]);export{f as __pageData,m as default};
